// ─── Placeholder / generic-phrase patterns ────────────────────────────────────

/** Patterns indicating vague or un-replaced generic phrases */
const GENERIC_PHRASE_PATTERNS: ReadonlyArray<RegExp> = [
  /various committees/iu,
  /several MEPs/iu,
